module binary_counter (
    input clk,
    input reset,
    output reg [3:0] count
);

    // 4-bit binary counter logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            count <= 4'b0000;
        else
            count <= count + 1;
    end

endmodule
